#import <Foundation/Foundation.h>
#include <stdlib.h> // For arc4random_uniform

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSLog(@"--- Random Numbers ---");

        // Generate a random integer within a specific range [min, max] (inclusive)
        // Using arc4random_uniform(upper_bound) which returns [0, upper_bound - 1]
        // This is generally preferred over rand() / srand()
        uint32_t minVal = 1;
        uint32_t maxVal = 100;
        uint32_t upperBound = maxVal - minVal + 1; // Number of values in range
        uint32_t randomInt = arc4random_uniform(upperBound) + minVal;
        NSLog(@"Random Integer [%u-%u]: %u", minVal, maxVal, randomInt);

        // Generate a random float between 0.0 and 1.0 (exclusive of 1.0)
        // Method 1: Using arc4random and division
        double randomDouble = (double)arc4random() / UINT32_MAX; // Divide by max possible uint32 value
        NSLog(@"Random Double [0.0, 1.0): %f", randomDouble);

        // Method 2: Using C's rand() after seeding (less preferred but common)
        // srand((unsigned)time(NULL)); // Seed once at program start
        // double randomDoubleRand = (double)rand() / RAND_MAX;
        // NSLog(@"Random Double (rand): %f", randomDoubleRand);


        // Select a random element from an NSArray
        NSArray<NSString *> *fruits = @[@"apple", @"banana", @"cherry"];
        if ([fruits count] > 0) {
            uint32_t randomIndex = arc4random_uniform((uint32_t)[fruits count]);
            NSString *randomFruit = fruits[randomIndex]; // Modern Objective-C literal subscripting
            // NSString *randomFruitOld = [fruits objectAtIndex:randomIndex]; // Older syntax
            NSLog(@"Random fruit: %@", randomFruit);
        }
    }
    return 0;
}

