#import <Foundation/Foundation.h>

// Helper function or category method is often used for complex string ops
@interface NSString (Reverse)
- (NSString *)reversedString;
@end

@implementation NSString (Reverse)
- (NSString *)reversedString {
    NSMutableString *reversed = [NSMutableString stringWithCapacity:[self length]];
    // Enumerate string by composed character sequences for Unicode correctness
    [self enumerateSubstringsInRange:NSMakeRange(0, [self length])
                             options:(NSStringEnumerationReverse | NSStringEnumerationByComposedCharacterSequences)
                          usingBlock:^(NSString *substring, NSRange substringRange, NSRange enclosingRange, BOOL *stop) {
        [reversed appendString:substring];
    }];
    return [reversed copy]; // Return immutable copy
}
@end


int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSString *originalString = @"Objective-C Example";
        NSLog(@"Original: %@", originalString);

        NSString *reversedStr = [originalString reversedString]; // Use category method
        NSLog(@"Reversed: %@", reversedStr);

        // Example with Unicode
        NSString *originalUnicode = @"你好 Objective-C"; // Make sure source file encoding is UTF-8
        NSLog(@"Original Unicode: %@", originalUnicode);
        NSString *reversedUnicode = [originalUnicode reversedString];
        NSLog(@"Reversed Unicode: %@", reversedUnicode);
    }
    return 0;
}

