#import <Foundation/Foundation.h>
// For BigInt, would need an external library like GMP, or potentially NSDecimalNumber for limited size.
// This uses 'long long' which covers up to ~F(92).

// Calculates the Nth Fibonacci number (0-indexed) iteratively
long long fibonacci(int n) {
    if (n < 0) {
        // In Obj-C, often return error code/nil or raise exception
        [NSException raise:@"InvalidArgumentException" format:@"Input must be non-negative"];
        return -1; // Should not be reached if exception raised
    }
    if (n == 0) return 0LL;
    if (n == 1) return 1LL;

    long long a = 0LL;
    long long b = 1LL;

    for (int i = 2; i <= n; ++i) {
        // Basic overflow check (can be complex to do perfectly)
        if (b > INT64_MAX - a) { // Check before addition
             NSLog(@"Warning: Fibonacci sequence overflowed long long near F(%d)", i);
             // Could raise, or just return current value or max value
        }
        long long next = a + b;
        a = b;
        b = next;
    }
    return b;
}

// Generates the first 'count' Fibonacci numbers as NSArray of NSNumber
NSArray<NSNumber *> * generateFibonacciSequence(int count) {
     if (count < 0) {
         [NSException raise:@"InvalidArgumentException" format:@"Count must be non-negative"];
         return nil;
     }
     NSMutableArray<NSNumber *> *sequence = [NSMutableArray arrayWithCapacity:count];
     for (int i = 0; i < count; ++i) {
         [sequence addObject:[NSNumber numberWithLongLong:fibonacci(i)]];
     }
     return [sequence copy]; // Return immutable copy
}


int main(int argc, const char * argv[]) {
    @autoreleasepool {
        int n = 10;
        @try {
            NSLog(@"Fibonacci number F(%d): %lld", n, fibonacci(n));

            int numTerms = 15;
            NSLog(@"First %d Fibonacci numbers:", numTerms);
            NSArray *sequence = generateFibonacciSequence(numTerms);
            NSLog(@"%@", [sequence componentsJoinedByString:@", "]); // Nice printing

            // Example with large number
            int largeN = 90;
             NSLog(@"Fibonacci number F(%d): %lld", largeN, fibonacci(largeN));

        } @catch (NSException *exception) {
            NSLog(@"Error calculating Fibonacci: %@", exception.reason);
        }
    }
    return 0;
}

