#import <Foundation/Foundation.h>
// Using unsigned long long for max range in standard types (Factorial 21+ overflows)
// Use NSDecimalNumber or external BigInt library for arbitrary precision.

// Calculates factorial N! iteratively
unsigned long long factorial(int n) {
    if (n < 0) {
        [NSException raise:@"InvalidArgumentException" format:@"Factorial input must be non-negative"];
        return 0; // Should not be reached
    }

    unsigned long long result = 1ULL; // Factorial of 0 is 1
    if (n == 0) {
        return result;
    }

    for (int i = 2; i <= n; ++i) {
         // Basic overflow check
         if (result > UINT64_MAX / i) {
              NSLog(@"Warning: Factorial overflowed unsigned long long near %d!", i);
              // Could return UINT64_MAX or raise exception
         }
        result *= i;
    }
    return result;
}

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        @try {
            int num = 5;
            NSLog(@"Factorial of %d is: %llu", num, factorial(num));

            num = 0;
            NSLog(@"Factorial of %d is: %llu", num, factorial(num));

            num = 20; // Max for signed long long, fits unsigned
            NSLog(@"Factorial of %d is: %llu", num, factorial(num));

            // num = 21; // Overflows unsigned long long
            // NSLog(@"Factorial of %d is: %llu (Overflow expected)", num, factorial(num));

            num = -3; // Invalid input
            factorial(num); // This will throw

        } @catch (NSException *exception) {
             NSLog(@"Error calculating factorial: %@", exception.reason);
        }
    }
    return 0;
}

