#import <Foundation/Foundation.h>
#include <math.h> // For sqrt

// Checks if a number is prime (using C logic)
BOOL isPrime(long long n) { // Use long long for a wider range
    if (n <= 1) return NO;
    if (n <= 3) return YES;
    if (n % 2 == 0 || n % 3 == 0) return NO;

    // Check factors from 5 upwards, stepping by 6
    long long limit = (long long)sqrt((double)n);
    for (long long i = 5; i <= limit; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) {
            return NO; // Divisor found
        }
    }
    return YES; // No divisors found
}

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        long long numbersToCheck[] = { 2LL, 3LL, 4LL, 17LL, 25LL, 29LL, 97LL, 100LL, 1LL, -5LL, 1000000007LL };
        int count = sizeof(numbersToCheck) / sizeof(numbersToCheck[0]);

        for (int i = 0; i < count; ++i) {
            long long n = numbersToCheck[i];
            if (isPrime(n)) {
                NSLog(@"%lld is prime.", n);
            } else {
                 NSLog(@"%lld is not prime.", n);
            }
        }
    }
    return 0;
}

