#import <Foundation/Foundation.h>

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSString *filePath = @"objc_read_test.txt";

        // Create a dummy file for reading
        NSString *dummyContent = @"Line 1 content from Objective-C.\nThis is the second line.\nEnd.";
        NSError *writeError = nil;
        BOOL writeOK = [dummyContent writeToFile:filePath atomically:YES encoding:NSUTF8StringEncoding error:&writeError];
        if (!writeOK) {
            NSLog(@"Error creating dummy file: %@", writeError);
            return 1; // Cannot proceed
        }
        NSLog(@"Created dummy file '%@' for reading.", filePath);


        NSLog(@"--- Reading file '%@' ---", filePath);
        NSFileManager *fileManager = [NSFileManager defaultManager];

        if ([fileManager fileExistsAtPath:filePath]) {
            NSError *readError = nil;

            // Method 1: Read entire file into NSString
            NSLog(@"\n--- Reading using stringWithContentsOfFile ---");
            NSString *fileContent = [NSString stringWithContentsOfFile:filePath
                                                              encoding:NSUTF8StringEncoding
                                                                 error:&readError];
            if (fileContent) {
                NSLog(@"File content as single string:");
                NSLog(@"%@", fileContent); // NSLog adds its own newline
                 NSLog(@"--- End of read all ---");
            } else {
                NSLog(@"Error reading file: %@", readError);
            }

            // Method 2: Read lines into NSArray
            // Reset error
            readError = nil;
            NSLog(@"\n--- Reading lines using componentsSeparatedByString ---");
            // Read all then split - less efficient for huge files than line-by-line
            NSString *fullContentForLines = [NSString stringWithContentsOfFile:filePath encoding:NSUTF8StringEncoding error:&readError];
            if (fullContentForLines) {
                NSArray<NSString *> *lines = [fullContentForLines componentsSeparatedByCharactersInSet:[NSCharacterSet newlineCharacterSet]];
                // Note: This might include an empty string at the end if file ends with newline
                NSLog(@"Read approx %lu lines:", (unsigned long)[lines count]);
                int lineNum = 1;
                for (NSString *line in lines) {
                     // Optional: skip empty line potentially caused by trailing newline
                     if ([line length] > 0 || lineNum < [lines count]) {
                        NSLog(@"Line %d: %@", lineNum, line);
                     }
                    lineNum++;
                }
                 NSLog(@"--- End of read lines ---");
            } else {
                 NSLog(@"Error reading file for lines: %@", readError);
            }

            // Clean up dummy file
            NSError *removeError = nil;
            [fileManager removeItemAtPath:filePath error:&removeError];
            if (removeError) { NSLog(@"Error cleaning up dummy file: %@", removeError); }
            else { NSLog(@"\nCleaned up dummy file '%@'.", filePath); }

        } else {
            NSLog(@"Error: File not found '%@'", filePath);
        }
    }
    return 0;
}

