#import <Foundation/Foundation.h>

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSString *filePath = @"output_objc.txt";
        NSArray<NSString *> *initialLines = @[
            @"First line written by Objective-C.",
            @"Second line using writeToFile."
        ];
        NSString *lineToAppend = @"Third line, appended using NSFileHandle.";

        // --- Write using NSString's writeToFile (overwrites or creates) ---
        NSLog(@"--- Writing to '%@' (overwrite) ---", filePath);
        NSString *initialContent = [initialLines componentsJoinedByString:@"\n"];
        initialContent = [initialContent stringByAppendingString:@"\n"]; // Add final newline
        NSError *writeError = nil;
        BOOL writeOK = [initialContent writeToFile:filePath
                                        atomically:YES // Safer, writes to temp then renames
                                          encoding:NSUTF8StringEncoding
                                             error:&writeError];
        if (writeOK) {
            NSLog(@"Successfully wrote %lu lines.", (unsigned long)[initialLines count]);
        } else {
            NSLog(@"Error writing to '%@': %@", filePath, writeError);
        }

        // --- Append using NSFileHandle ---
        NSLog(@"\n--- Appending to '%@' ---", filePath);
        NSFileHandle *fileHandle = nil;
        @try {
            fileHandle = [NSFileHandle fileHandleForWritingAtPath:filePath];
            if (fileHandle == nil) {
                // If file doesn't exist, writeToFile should have created it,
                // but handle case where it might have failed or been deleted.
                // Or, create it here if needed for appending.
                 NSLog(@"Warning: File handle couldn't be opened for writing (might not exist). Appending might fail or create.");
                 // For robustness, could attempt to create/write here if nil
                 [lineToAppend writeToFile:filePath atomically:YES encoding:NSUTF8StringEncoding error:nil];
            } else {
                [fileHandle seekToEndOfFile]; // Go to the end
                NSData *dataToAppend = [[lineToAppend stringByAppendingString:@"\n"] dataUsingEncoding:NSUTF8StringEncoding];
                [fileHandle writeData:dataToAppend];
                NSLog(@"Successfully appended content.");
            }
        } @catch (NSException *exception) {
            NSLog(@"Error appending to '%@': %@", filePath, exception.reason);
        } @finally {
            [fileHandle closeFile]; // Close the handle if it was opened
        }


        // --- Display final content ---
        NSLog(@"\n--- Final content of '%@': ---", filePath);
        NSError *readError = nil;
        NSString *finalContent = [NSString stringWithContentsOfFile:filePath encoding:NSUTF8StringEncoding error:&readError];
        if (finalContent) {
            NSLog(@"%@", finalContent);
        } else {
             NSLog(@"File '%@' not found or cannot be read for display.", filePath);
        }

        // Optional: Clean up
        // NSError *removeError = nil;
        // [[NSFileManager defaultManager] removeItemAtPath:filePath error:&removeError];

    }
    return 0;
}

