#import <Foundation/Foundation.h>

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSString *fileToCheck = @"objc_exists_test.m";
        NSString *dirToCheck = @"MyObjCFolder";
        NSString *nonExistent = @"NoSuchThingHereObjC.xyz";

        NSFileManager *fileManager = [NSFileManager defaultManager];

        // Create dummy file/dir
        NSLog(@"Creating dummy file and directory...");
        NSError *error = nil;
        [@"// ObjC test file" writeToFile:fileToCheck atomically:NO encoding:NSUTF8StringEncoding error:&error];
        if (error) NSLog(@"Error creating file: %@", error);
        error = nil; // Reset error
        [fileManager createDirectoryAtPath:dirToCheck withIntermediateDirectories:YES attributes:nil error:&error];
         if (error) NSLog(@"Error creating directory: %@", error);


        NSLog(@"\n--- Checking Existence and Type using NSFileManager ---");

        // fileManager fileExistsAtPath: - Checks if something exists at path
        NSLog(@"'%@' exists? %d", fileToCheck, [fileManager fileExistsAtPath:fileToCheck]);     // 1 (YES)
        NSLog(@"'%@' exists? %d", dirToCheck, [fileManager fileExistsAtPath:dirToCheck]);      // 1 (YES)
        NSLog(@"'%@' exists? %d", nonExistent, [fileManager fileExistsAtPath:nonExistent]);    // 0 (NO)


        // To distinguish between file and directory:
        BOOL isDir;
        // Check file specifically
        BOOL fileExists = [fileManager fileExistsAtPath:fileToCheck isDirectory:&isDir];
        NSLog(@"\nChecking '%@':", fileToCheck);
        if (fileExists && !isDir) {
            NSLog(@" -> Exists as a FILE.");
        } else if (fileExists && isDir) {
             NSLog(@" -> Exists but is a DIRECTORY.");
        } else {
             NSLog(@" -> Does NOT exist.");
        }

         // Check directory specifically
        BOOL dirExists = [fileManager fileExistsAtPath:dirToCheck isDirectory:&isDir];
        NSLog(@"\nChecking '%@':", dirToCheck);
        if (dirExists && isDir) {
            NSLog(@" -> Exists as a DIRECTORY.");
        } else if (dirExists && !isDir) {
             NSLog(@" -> Exists but is a FILE.");
        } else {
             NSLog(@" -> Does NOT exist.");
        }

        // Clean up
        NSLog(@"\nCleaning up...");
        [fileManager removeItemAtPath:fileToCheck error:nil]; // Ignore errors for cleanup
        [fileManager removeItemAtPath:dirToCheck error:nil];
        NSLog(@"Cleanup attempt finished.");

    }
    return 0;
}

