#import <Foundation/Foundation.h>

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        NSLog(@"--- Current Date and Time ---");

        // Get current date and time as an NSDate object (represents a point in time, independent of timezone)
        NSDate *now = [NSDate date];
        NSLog(@"Current NSDate object (UTC based): %@", now);

        // To display in local time or specific formats, use NSDateFormatter
        NSDateFormatter *formatter = [[NSDateFormatter alloc] init];

        NSLog(@"\n--- Common Formats (using NSDateFormatter) ---");
        // Predefined styles (depend on user's locale settings)
        formatter.dateStyle = NSDateFormatterShortStyle; // e.g., 3/30/25
        formatter.timeStyle = NSDateFormatterNoStyle;
        NSLog(@"Short Date (locale): %@", [formatter stringFromDate:now]);

        formatter.dateStyle = NSDateFormatterLongStyle; // e.g., March 30, 2025
        NSLog(@"Long Date (locale): %@", [formatter stringFromDate:now]);

        formatter.dateStyle = NSDateFormatterNoStyle;
        formatter.timeStyle = NSDateFormatterMediumStyle; // e.g., 8:23:43 PM
        NSLog(@"Medium Time (locale): %@", [formatter stringFromDate:now]);

        formatter.dateStyle = NSDateFormatterFullStyle; // e.g., Sunday, March 30, 2025 at ...
        formatter.timeStyle = NSDateFormatterFullStyle;
        NSLog(@"Full Date & Time (locale): %@", [formatter stringFromDate:now]);


        NSLog(@"\n--- Custom Formats (using setDateFormat:) ---");
        // Uses Unicode Technical Standard #35 (UTS #35) format patterns
        // See: https://unicode.org/reports/tr35/tr35-dates.html#Date_Field_Symbol_Table
        [formatter setDateFormat:@"yyyy-MM-dd"];
        NSLog(@"YYYY-MM-DD: %@", [formatter stringFromDate:now]);

        [formatter setDateFormat:@"HH:mm:ss"]; // 24-hour
        NSLog(@"HH:mm:ss (24hr): %@", [formatter stringFromDate:now]);

        // Set locale for consistent month/day names if needed
        // formatter.locale = [NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"];
        [formatter setDateFormat:@"EEEE, MMMM dd, yyyy 'at' hh:mm:ss a zzzz"]; // EEEE=Day, MMMM=Month, a=AM/PM, zzzz=Timezone Name
        NSLog(@"Readable: %@", [formatter stringFromDate:now]);


        NSLog(@"\n--- Components (using NSCalendar) ---");
        NSCalendar *calendar = [NSCalendar currentCalendar]; // User's current calendar
        // Specify which components are needed
        NSCalendarUnit units = NSCalendarUnitYear | NSCalendarUnitMonth | NSCalendarUnitDay |
                               NSCalendarUnitHour | NSCalendarUnitMinute | NSCalendarUnitSecond |
                               NSCalendarUnitWeekday | NSCalendarUnitDay; // Fixed: Duplicate Day
        NSDateComponents *components = [calendar components:units fromDate:now];

        NSLog(@"Year: %ld", (long)[components year]);
        NSLog(@"Month: %ld", (long)[components month]);
        NSLog(@"Day: %ld", (long)[components day]);
        NSLog(@"Hour: %ld", (long)[components hour]);
        NSLog(@"Minute: %ld", (long)[components minute]);
        NSLog(@"Second: %ld", (long)[components second]);
        NSLog(@"DayOfWeek: %ld (1=Sun, 2=Mon,...)", (long)[components weekday]);
        // DayOfYear needs NSCalendarUnitDay as well, calculated differently
        // NSInteger dayOfYear = [calendar ordinalityOfUnit:NSCalendarUnitDay inUnit:NSCalendarUnitYear forDate:now];
        // NSLog(@"DayOfYear: %ld", (long)dayOfYear);


        NSLog(@"\n--- Unix Epoch Seconds ---");
        NSTimeInterval epochSeconds = [now timeIntervalSince1970]; // Returns double
        NSLog(@"Seconds since epoch (double): %f", epochSeconds);
        NSLog(@"Seconds since epoch (long long): %lld", (long long)epochSeconds);

    }
    return 0;
}

