#import <Foundation/Foundation.h>

int main(int argc, const char * argv[]) {
    @autoreleasepool {
        // Example with NSArray of NSNumber objects
        NSArray<NSNumber *> *numbers = @[@10, @5, @42, @17, @8, @99, @32, @-5, @0];
        NSLog(@"Array: [%@]", [numbers componentsJoinedByString:@", "]);

        if ([numbers count] == 0) {
             NSLog(@"Array is empty, cannot find maximum.");
        } else {
            // Method 1: Using Key-Value Coding (KVC) Collection Operators (concise)
            // Requires array elements to be NSNumber or other KVC compliant objects
            NSNumber *maxValueKVC = [numbers valueForKeyPath:@"@max.self"];
            NSLog(@"Maximum value (KVC @max): %@", maxValueKVC);

            // Method 2: Manual iteration
            NSNumber *currentMax = numbers[0]; // Assume non-empty based on check
            for (NSNumber *num in numbers) {
                // Use compare: method (NSOrderedAscending, NSOrderedSame, NSOrderedDescending)
                if ([num compare:currentMax] == NSOrderedDescending) {
                    currentMax = num;
                }
            }
             NSLog(@"Maximum value (Manual loop): %@", currentMax);
        }


        // Example with strings (lexicographical maximum)
        NSArray<NSString *> *strings = @[@"apple", @"banana", @"zebra", @"cherry"];
         NSLog(@"\nArray: [%@]", [strings componentsJoinedByString:@", "]);
         if ([strings count] > 0) {
             NSString *maxStringKVC = [strings valueForKeyPath:@"@max.self"]; // Works for strings too
             NSLog(@"Maximum value (KVC @max): %@", maxStringKVC);

             // Manual loop for strings
             NSString *currentMaxStr = strings[0];
             for(NSString *str in strings) {
                if ([str compare:currentMaxStr] == NSOrderedDescending) {
                    currentMaxStr = str;
                }
             }
             NSLog(@"Maximum value (Manual loop): %@", currentMaxStr);
         }


        // Example empty array
        NSArray *emptyArray = @[];
        NSLog(@"\nArray: []");
        if ([emptyArray count] == 0) {
            NSLog(@"Cannot find maximum in an empty array.");
            // NSNumber *maxEmpty = [emptyArray valueForKeyPath:@"@max.self"]; // Returns nil for empty
            // NSLog(@"Max (KVC, empty): %@", maxEmpty);
        }

    }
    return 0;
}
